mapper.select:
SELECT ls.id, ls.part_code AS partCode, ls.part_name AS partName, ls.standard_code AS standardCode, ls.standard_name AS standardName, ls.method, ls.profession, ls.oil_feed_type AS oilFeedType, ls.feed_point AS feedPoint, ls.oil_models AS oilModels, ls.oil_volume AS oilVolume, ls.next_check_time AS nextCheckTime, ls.creator_id AS creatorId, ls.created_at AS createdAt, ls.updated_at AS updatedAt FROM lubrication_standard ls LEFT JOIN equipment_part ep ON ls.part_code = ep.part_code AND ep.creator_id = ls.creator_id LEFT JOIN equipment e ON ep.equipment_id = e.id AND e.creator_id = ls.creator_id LEFT JOIN device_unit du ON e.device_unit_id = du.id AND du.creator_id = ls.creator_id
AND ls.creator_id = #{creatorId} AND du.production_line_id = #{productionLineId} AND e.device_unit_id = #{deviceUnitId} AND ep.equipment_id = #{equipmentId} AND ls.standard_code LIKE CONCAT('%', #{standardCode}, '%') AND ls.part_code LIKE CONCAT('%', #{partCode}, '%') AND ls.part_name LIKE CONCAT('%', #{partName}, '%') AND ls.feed_point LIKE CONCAT('%', #{feedPoint}, '%') AND ls.oil_models LIKE CONCAT('%', #{oilModels}, '%') AND ls.profession = #{profession} AND ls.oil_feed_type = #{oilFeedType}
ORDER BY ls.id DESC

mapper.update:
UPDATE lubrication_standard
part_code = #{record.partCode}, part_name = #{record.partName}, standard_code = #{record.standardCode}, standard_name = #{record.standardName}, method = #{record.method}, profession = #{record.profession}, oil_feed_type = #{record.oilFeedType}, feed_point = #{record.feedPoint}, oil_models = #{record.oilModels}, oil_volume = #{record.oilVolume}, next_check_time = #{record.nextCheckTime}, updated_at = #{record.updatedAt},
WHERE id = #{record.id} AND creator_id = #{creatorId}

mapper.delete:
DELETE FROM lubrication_standard
WHERE id = #{id}
AND creator_id = #{creatorId}
